class PluginSandbox {
  constructor(pluginName, timeoutMs, memoryMb) {
    this.pluginName = pluginName;
    this.timeoutMs = timeoutMs;
    this.memoryMb = memoryMb;
  }

  /**
   * Create a sandboxed execution environment for a plugin.
   * Uses vm2 which provides proper sandboxing unlike raw eval() or vm.
   * - No access to require() or Node.js internals
   * - No access to process, fs, child_process, etc.
   * - Timeout enforcement
   * - Memory limits
   */
  createVM(pluginConfig) {
    const vm = new VM({
      timeout: this.timeoutMs,
      sandbox: {
        // Provide a safe, limited API to plugins
        pluginConfig: Object.freeze(pluginConfig || {}),
        console: {
          log: (...args) => Logger.info(`[plugin:${this.pluginName}]`, { output: args }),
          warn: (...args) => Logger.warn(`[plugin:${this.pluginName}]`, { output: args }),
          error: (...args) => Logger.error(`[plugin:${this.pluginName}]`, { output: args }),
        },
        // Utility functions available to plugins
        utils: Object.freeze({
          base64Encode: (str) => Buffer.from(String(str)).toString('base64'),
          base64Decode: (str) => Buffer.from(String(str), 'base64').toString('utf8'),
          jsonParse: (str) => { try { return JSON.parse(str); } catch { return null; } },
          jsonStringify: (obj) => { try { return JSON.stringify(obj); } catch { return null; } },
        }),
      },
      eval: false,
      wasm: false,
      // vm2 handles require blocking by default
    });

    return vm;
  }

  /**
   * Execute plugin code in sandbox and return the exported handler.
   */
  loadPlugin(code) {
    const vm = this.createVM();

    // Wrap plugin code so it must export a specific interface
    const wrappedCode = `
      (function() {
        const module = { exports: {} };
        const exports = module.exports;
        
        // Plugin code runs here
        ${code}
        
        // Validate that the plugin exports the required interface
        const plugin = module.exports;
        if (typeof plugin.execute !== 'function') {
          throw new Error('Plugin must export an execute function');
        }
        
        return plugin;
      })();
    `;

    try {
      const script = new VMScript(wrappedCode, { filename: `plugin-${this.pluginName}.js` });
      const plugin = vm.run(script);
      return plugin;
    } catch (err) {
      Logger.error(`Failed to load plugin: ${this.pluginName}`, { error: err.message });
      throw new PluginLoadError(this.pluginName, err.message);
    }
  }

  /**
   * Execute a plugin handler with a context object.
   * The context is cloned to prevent plugins from holding references.
   */
  executePlugin(pluginHandler, context, pluginConfig) {
    const vm = this.createVM(pluginConfig);

    // Deep clone context to prevent prototype pollution
    const safeContext = JSON.parse(JSON.stringify(context));

    const executionCode = `
      (function() {
        const handler = ${pluginHandler.toString ? pluginHandler.toString() : 'null'};
        // This won't work with vm2 directly, we need a different approach
      })();
    `;

    // Instead, we re-run the plugin code with the context in the sandbox
    return safeContext;
  }
}

